const ADD_POST = "ADDPOST";
const NEW_POST = "NEWPOST";
let initialState = {
  messegData: [],
  newChanges: "",
};
const messegDataReducer = (state = initialState, action) => {
  switch (action.type) {
    case NEW_POST: {
      let newStare = { ...state };
      newStare.newChanges = action.newChange;
      return newStare;
    }
    case ADD_POST:
      let newPost = {
        id: 5,
        messege: state.newChanges,
        like: 23,
      };
      let newStare = { ...state };
      newStare.messegData = [...state.messegData];
      newStare.messegData.push(newPost);
      state.newChanges = "";
      return newStare;
    default:
      return state;
  }
};

export const addPostcreateActin = () => ({ type: ADD_POST });

export const onPostChangecreateActin = (text) => ({
  type: NEW_POST,
  newChange: text,
});
export default messegDataReducer;
